\begin{proof}[Proof of Theorem \ref{thm:quadratic_approximation}]
See Figure \ref{fig_qudratic_proof_illu} for an illustration of the proof. 
We define   
$D_{\ell} := \prod_{i=1}^{\ell} d_{i}$ for $\ell \in [L]$.
The construction of the network is done by induction with respect to the layer $\ell$ via the following three steps:
\begin{enumerate}
    \item[(i)] Let $\bz_{\ell}(x) = (z_{\ell, j}(x))_{j=0}^{d_{\ell}-1}$ be the values of the $d_{\ell}$ hidden neurons in the $\ell$-th hidden layer.
    \item[(ii)] We define three functions $u_\ell(x), \phi_\ell(x)$ and $\psi_\ell(x)$,
    which are non-negative affine combinations of $\bz_{\ell}(x)$.
    \item[(iii)] We define $\bz_{\ell+1}(x) = (z_{\ell+1, j}(x))_{j=0}^{d_{\ell+1}-1}$ via \eqref{tmp_14} and \eqref{tmp_13}. Since $u_\ell(x), \phi_\ell(x)$ and $\psi_\ell(x)$ are non-negative affine combinations of $\bz_{\ell}(x)$, $\bz_{\ell+1}(x)$ is of the form
    $\max (V_\ell^{1} \bz_{\ell}(x) + \bw_{\ell}^{1} x + \bb_{\ell}^{1}, V_\ell^{2} \bz_{\ell}(x) + \bw_{\ell}^{2} x + \bb_{\ell}^{2})$ with element-wise non-negative $V_\ell^{1}$ and $V_\ell^{2}$.
\end{enumerate}

We begin the induction with the first hidden layer $\ell=1$.
In the first hidden layer, we construct $d_1-1$ functions  $\bz_{1}(x) = (z_{1,j}(x))_{j=1}^{d_{1}-1}$ of the form
\begin{align}
z_{1,j}(x) := \left(x - \frac{j}{d_1}\right)_+  \text{ for } j \in [d_1-1]. \label{tmp_15}
\end{align}
Only $d_1 - 1$ neurons are used here.
We consider three non-negative affine combinations of $\bz_{1}(x)$:
\begin{align*}
    u_1(x) &:=  \sum_{k=1}^{d_1-1} \frac{2}{d_1} \left(x - \frac{k}{d_1}\right)_+,\\
    \phi_1(x) &:= \sum_{k=1}^{d_1-1} \big(a_1\mathds{1}(k\text{ odd}) + b\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{d_1}\right)_+,\\
    \psi_1(x) &:= \sum_{k=1}^{d_1-1} \big(b\mathds{1}(k\text{ odd}) + a_1\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{d_1}\right)_+
\end{align*}
with $a_1 := 4/d_1$ and $b := 4/(L D_{\ell})$. This proves step (ii) for $\ell=1.$

Let
$$a_{\ell+1}:= \frac{a_\ell - (d_{\ell+1}-1) b}{d_{\ell+1}}.$$
This implies that $a_\ell \geq (L+1-\ell) (\prod_{i=\ell+1}^L d_i) b\geq b$ for every $\ell \in [L]$. Indeed, this is true for $\ell=1$ as $a_1 = L (\prod_{i=2}^L d_i) b_1$. Moreover, if $a_\ell \geq (L+1-\ell) (\prod_{i=\ell+1}^L d_i) b$, then
$$a_{\ell+1} \geq \frac{a_\ell - d_{\ell+1} b}{d_{\ell+1}} \geq \frac{(L-\ell) (\prod_{i=\ell+1}^L d_i) b}{d_{\ell+1}} = (L-\ell) \Big(\prod_{i=\ell+2}^L d_i\Big) b.$$

We now describe the induction step $\ell \to \ell+1,$ assuming that for a given $\ell \in [L-1],$ 
\begin{align}
    u_\ell(x) &:=  \sum_{k=1}^{D_{\ell}-1} \frac{2}{D_{\ell}} \left(x - \frac{k}{D_{\ell}}\right)_+, \label{def_u_ell_0}\\
    \phi_\ell(x) &:= \sum_{k=1}^{D_{\ell}-1} \big(a_\ell\mathds{1}(k\text{ odd}) + b\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell}}\right)_+,
    \label{def_u_ell_1} \\
    \psi_\ell(x) &:= \sum_{k=1}^{D_{\ell}-1} \big(b\mathds{1}(k\text{ odd}) + a_\ell\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell}}\right)_+,
    \label{def_u_ell_2}
\end{align}
are non-negative affine combinations of the values of the neurons in the $\ell$-th hidden layer $\bz_{\ell}(x) = (z_{\ell, j}(x))_{j=0}^{d_{\ell}-1}.$

\begin{figure}[h!] 
  \centering  \includegraphics[width=.97\textwidth]{../figures/approximation_qudratic_d4.pdf}
  \caption{\textbf{Illustration of the proof of Theorem \ref{thm:quadratic_approximation}} for $L=2$ and $(d_1, d_2)=(4,4)$. 
  $u_{\ell}(x)$, $\phi_{\ell}(x)$ and $\psi_{\ell}(x)$ are defined by \eqref{def_u_ell_0}, \eqref{def_u_ell_1} and \eqref{def_u_ell_2}, respectively.  
  From \eqref{tmp_14} and \eqref{tmp_13}, 
  $z_{2,0}(x) = u_{1}(x)$ and
    $z_{2,j}(x)=\max(\phi_1(x), \psi_1(x) + \frac{7}{16} x - \frac{7j}{256})$ for $j \in \{1,2,3\}.$ Gray vertical lines are drawn at the kink locations of the functions.}
    \label{fig_qudratic_proof_illu}
\end{figure}

In the $(\ell+1)$-st hidden layer, we can construct $d_{\ell+1}$ neurons with 
\begin{align}
    z_{\ell+1, 0}(x) \coloneq \max\big( u_\ell(x), 0 \big) 
    %
    =u_\ell(x)=  \sum_{k=1}^{D_{\ell}-1} \frac{2}{D_{\ell}} \left(x - \frac{k}{D_{\ell}}\right)_+
    \label{tmp_14}
\end{align}
and 
\begin{align}
    z_{\ell+1, j}(x)
    &\coloneq \max\left(\phi_\ell(x), \psi_\ell(x) + \frac{a_\ell - b}{2} x - \frac{(a_\ell - b)j}{2D_{\ell+1}} \right). \label{tmp_13}
\end{align}
for $j \in [d_{\ell+1}-1]$. The following two lemmas complete the induction step. Their proofs are given below.
\begin{lemma} \label{lemma_z_equal} For each $j \in \{1,\ldots, d_{\ell+1}-1\}$, $z_{\ell+1, j}(x)$ defined by \eqref{tmp_13} equals
\begin{align*} \sum_{k=1}^{D_{\ell}-1} b \,  \Big(x - \frac{k}{D_{\ell}}\Big)_++  \sum_{k=0}^{D_{\ell}-1}  \frac{a_\ell - b}{2} \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{D_{\ell+1}}\Big)_+ \right).
\end{align*}
\end{lemma}

\begin{lemma}\label{lemma_u_affine}
    If $d_{\ell+1}$ is even, then, the functions $u_{\ell+1}$, $\phi_{\ell+1}$, and $\psi_{\ell+1}$, defined by
    \begin{align*}
    u_{\ell+1}(x) &:=  \sum_{k=1}^{D_{\ell+1}-1} \frac{2}{D_{\ell+1}} \left(x - \frac{k}{D_{\ell+1}}\right)_+,\\
    \phi_{\ell+1}(x) &:= \sum_{k=1}^{D_{\ell+1}-1} \big(a_{\ell+1}\mathds{1}(k\text{ odd}) + b\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell+1}}\right)_+,\\
    \psi_{\ell+1}(x) &:= \sum_{k=1}^{D_{\ell+1}-1} \big(b\mathds{1}(k\text{ odd}) + a_{\ell+1}\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell+1}}\right)_+,
\end{align*}
    are non-negative affine combinations of $(z_{\ell+1, j}(x))_{j=0}^{d_{\ell+1}-1}$, defined by \eqref{tmp_14} and \eqref{tmp_13}.
\end{lemma}
Hence, by Lemma \ref{lemma_u_affine} and the induction argument, the function 
$$u_{L}(x) :=  \sum_{k=1}^{D_{L}-1} \frac{2}{D_{L}} \left(x - \frac{k}{D_{L}}\right)_+$$
is a non-negative affine combinations of the last hidden layer $\bz_{L}(x)$.
The final output of the network is then given by
\begin{align}
    f(x) \coloneqq - \frac{1}{8 D_{L}^2} + \frac{x}{D_{L}} + u_{L}(x) = - \frac{1}{8 D_{L}^2} + \frac{x}{D_{L}} + \frac{2}{D_{L}}\sum_{k=1}^{D_{L}-1} \left(x - \frac{k}{D_{L}}\right)_+.
    \label{tmp_16}
\end{align}
Finally, by applying Lemma \ref{lemma_sq_approx_pc}, we have $|x^2-f(x)| \leq 1/(8 D_{L}^2)$ and obtain the assertion.
\end{proof}

\begin{proof}[Proof of Lemma \ref{lemma_z_equal}]
    We fix $\ell \in \NN$, $j \in [d_{\ell+1}-1]$ and recall that $D_{\ell} = \prod_{i=1}^{\ell} d_{i}$ and
\begin{align*}
    \phi_\ell(x) &= \sum_{k=1}^{D_{\ell}-1} \big(a_\ell\mathds{1}(k\text{ odd}) + b\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell}}\right)_+,\\
    \psi_\ell(x) &= \sum_{k=1}^{D_{\ell}-1} \big(b\mathds{1}(k\text{ odd}) + a_\ell\mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell}}\right)_+.
\end{align*}    
    Further, we write $\Delta \coloneq \Delta_{\ell} = a_\ell - b \geq 0$ and  
\begin{align*}
\mathcal{L}(x):= - \frac{\Delta j}{2 D_{\ell} d_{\ell+1}} + \frac{\Delta}{2}\,x , \qquad 
F(x):=\max\Bigl(\phi_\ell(x),\,\mathcal{L}(x)+\psi_\ell(x)\Bigr).
\end{align*}
We prove that on $[0,1]$
\begin{align*}
F(x)=\sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \frac{\Delta}{2} \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{ D_{\ell+1}}\Big) \right).
\end{align*}
The proof is divided into multiple steps.

\emph{Step 1: Slopes and switching locations.}
Define
\begin{align*}
    t(x) &\coloneqq \mathcal{L}(x) + \psi_\ell(x) - \phi_\ell(x) \\
    &= - \frac{\Delta j}{2 D_{\ell} d_{\ell+1}} + \frac{\Delta}{2}\,x + \sum_{k=1}^{D_{\ell}-1} \big( - \Delta \mathds{1}(k\text{ odd}) + \Delta \mathds{1}(k\text{ even})\big) \left(x - \frac{k}{D_{\ell}}\right)_+.
\end{align*}
Then, $t$ is a continuous and piecewise affine function. Moreover, on each open interval  
$I_k \coloneqq (\frac{k}{D_{\ell}},\frac{k+1}{D_{\ell}})$ for $k =0,\dots,D_{\ell}-1$,
\begin{align} \label{eq:slope-d_2}
    t'(x) = \frac{\Delta}{2} + \sum_{i=1}^k (-1)^i \Delta = (-1)^k \frac{\Delta}{2}.
\end{align}
We have
$t(0)=-\Delta j (2 D_{\ell} d_{\ell+1})^{-1}<0$. Using \eqref{eq:slope-d_2} and induction over $k = 0,1,\ldots, D_{\ell}-1$, it follows that 
\begin{align*}
t\!\left(\frac{k}{D_{\ell}}\right)
=\begin{cases}
-\frac{j}{d_{\ell+1}} \, \frac{\Delta}{2 D_{\ell} }, & k \text{ even},\\
(1-\frac{j}{d_{\ell+1}}) \frac{\Delta}{2 D_{\ell} }, & k \text{ odd}.
\end{cases}
\end{align*}
Thus on every $I_k$ the continuous piecewise affine function $t$ changes sign exactly once at
\begin{align*}
x_k:= 
\begin{cases}
\frac{k}{D_{\ell}} + \frac{j}{d_{\ell+1}} \, \frac{1}{D_{\ell}}, & k \text{ even},\\
\frac{k}{D_{\ell}} + \frac{d_{\ell+1} - j}{d_{\ell+1}} \, \frac{1}{D_{\ell}} , & k \text{ odd}.
\end{cases}
\end{align*}
Consequently, on $I_k$ we have 
\begin{align} \label{tmp_31}
    F= \begin{cases}
        \phi_\ell &\text{ on }(0,x_0)\cup (x_{1}, x_2) \cup (x_{3}, x_4) \cup \ldots \cup (x_{D_{\ell}-1}, 1)\\
        \mathcal{L}+ \psi_\ell &\text{ on } (x_0, x_1) \cup (x_2,x_3) \cup \ldots \cup (x_{D_{\ell}-2}, x_{D_{\ell}-1}).
    \end{cases}
\end{align}
In particular,
$F$ is piecewise-affine on $[0,1]$ with kinks at
\begin{align}
     \Bigl\{\tfrac{k}{D_{\ell}}: k=1,\dots,D_{\ell}-1\Bigr\} 
     \cup
    \Bigl\{x_k: k=0,\dots,D_{\ell}-1\Bigr\},
\label{tmp_6}
\end{align}
In addition, $F(0)=0$ and $F'(0)=0.$

\emph{Step 2: Jump heights of the derivative.}
For a real-valued function $f:\RR \to \RR$ which has right and left derivatives, we define the jump height of $f'$ as 
$$[\![ f ]\!](x) := \lim_{h\downarrow 0}\frac{f(x+h)-f(x)}{h} - \lim_{h\uparrow 0}\frac{f(x+h)-f(x)}{h}.$$
At each coarse grid point $\frac{k}{D_{\ell}}$ for $k \in [D_{\ell}-1]$, we pass from 
$I_{k-1}$ to $I_k$. 
By \eqref{tmp_31}  the jump height of $F'$ at $\frac{k}{D_{\ell}} \in (x_{k-1},x_k)$ is 
\begin{align}
    [\![F]\!]\Big(\frac{k}{D_{\ell}}\Big) &= \begin{cases}
    [\![\phi_\ell]\!](\frac{k}{D_{\ell}}) = b, & k \text{ even},\\
    [\![\mathcal{L} + \psi_\ell]\!](\frac{k}{D_{\ell}}) = b, & k \text{ odd}.
    \end{cases}\label{tmp_7}
\end{align}
At each kink $x_k$ the active branch switches, and by \eqref{eq:slope-d_2}
the jump height of $F'$ equals
\begin{align}
[\![F]\!](x_k)&=(-1)^k \bigl(( \mathcal{L} +\psi_\ell)'-(\phi_\ell)'\bigr)\big|_{x_k}=\frac{\Delta}{2}. \label{tmp_8}
\end{align}
Since every jump height of $F'$ on $[0,1]$ is non-negative, $F$ is convex.

\emph{Step 3: Hinge representation.}
Let $G$ be convex, piecewise-affine on $[0,1]$ with $G(0)=G'(0)=0$, and let
$\{\delta_m\}$ be its kink locations with jump height $\alpha_m > 0$ of $G'$ at $\delta_m$.
Then $G'(x)=\sum_m \alpha_m \,\1(x>\delta_\ell)$ on $x \in [0,1] \setminus \{\delta_m\}$, hence
\begin{align*}
G(x)=\int_0^x G'(u)\,du=\sum_m \alpha_m\,\pp{x-\delta_m}.
\end{align*}
Applying this to $G=F$ with kink locations obtained in \eqref{tmp_6} and jump heights
obtained in \eqref{tmp_7} and \eqref{tmp_8} finally yields
\begin{align*}
F(x)=\sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \frac{\Delta}{2} \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{ D_{\ell+1}}\Big)
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{ D_{\ell+1}}\Big) \right).
\end{align*}
\end{proof}

