\begin{proof}[Proof of Lemma \ref{lemma_u_affine}]
Lemma \ref{lemma_z_equal} states that
\begin{align*}
    z_{\ell+1, j}(x) =& \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+ \\
&+ \sum_{k=0}^{D_{\ell}-1} \frac{\Delta_{\ell}}{2} \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{D_{\ell+1}}\Big)_+ \right).
\end{align*}
We define constants $r_1, \ldots, r_{d_{\ell+1}-1}$ as 
\begin{align}
r_j := \frac{2a_{\ell+1}}{\Delta_{\ell}} \mathds{1}(j\text{ odd}) + \frac{2b}{\Delta_{\ell}} \mathds{1}(j\text{ even}).
\label{tmp_10}
\end{align}
By assumption $d_{\ell+1}$ is even, $a_{\ell+1}= (a_\ell - (d_{\ell+1}-1) b)/d_{\ell+1},$ and therefore
\begin{align}
    \sum_{j=1}^{d_{\ell+1}-1} r_j
&= \frac{d_{\ell+1}}{2} \, \frac{2a_{\ell+1}}{\Delta_{\ell}} + \frac{d_{\ell+1}-2}{2} \, \frac{2b}{\Delta_{\ell}}= \frac{a_\ell - (d_{\ell+1}-1) b + (d_{\ell+1}-2)b}{\Delta_{\ell}} =1. \label{tmp_9}
\end{align}
It follows
\begin{align*}
    \sum_{j=1}^{d_{\ell+1}-1} r_j \, z_{\ell+1}^{(j)}(x) 
    &= 
    \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+\\
    & \quad  + \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \frac{r_j \Delta_{\ell}}{2} 
    \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{D_{\ell+1}}\Big)_+ \right)\\
&= \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \frac{r_j \Delta_{\ell}}{2} 
    \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+\\
&= \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \Big( a_{\ell+1} \mathds{1}(j\text{ odd}) + b \mathds{1}(j\text{ even}) \Big) 
    \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+\\
&= \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k d_{\ell+1}}{D_{\ell+1}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \Big( a_{\ell+1} \mathds{1}(j\text{ odd}) + b \mathds{1}(j\text{ even}) \Big) 
    \Big(x - \frac{k d_{\ell+1} + j}{D_{\ell+1}}\Big)_+\\
    & = \sum^{D_{\ell+1}-1}_{q=1} \Big( a_{\ell+1} \mathds{1}(q\text{ odd}) + b \mathds{1}(q\text{ even}) \Big) \Big(x - \frac{q}{D_{\ell+1}}\Big)_+ \\
    &=:u^{(1)}_{\ell+1}(x).
\end{align*}
We used \eqref{tmp_9} and \eqref{tmp_10} for the first and third equality, the second equality uses that $d_{\ell+1}$ is even, and the fourth equality expands $q=kd_{\ell+1}+j.$ Since $d_{\ell+1}$ is even, $q$ is even if and only if $j$ is even. Hence $u^{(1)}_{\ell+1}(x)$ is a non-negative affine combination of $(z^{(0)}_{\ell+1}(x))_{j=0}^{d_{\ell+1}-1}$.

Similarly, define $$s_0 := \frac{D_{\ell}}{2} \,\Big(a_{\ell+1} - b \sum_{j=1}^{d_{\ell+1}-1} s_j \Big), \quad \text{and} \quad s_j := \frac{2b}{\Delta_{\ell}}  \mathds{1}(j\text{ odd}) + \frac{2a_{\ell+1}}{\Delta_{\ell}}  \mathds{1}(j\text{ even}),\quad j=1,\ldots,d_{\ell+1}-1.$$
From  $\sum_{j=1}^{d_{\ell+1}-1} s_j \leq \sum_{j=1}^{d_{\ell+1}-1} r_j =1$, we get $s_0 \geq 0$.
Moreover,
\begin{align}
    \frac{2s_0}{D_{\ell}} + b \sum_{j=1}^{d_{\ell+1}-1} s_j
&= a_{\ell+1}, \label{tmp_11}
\end{align}
and for $j \in \{1,\ldots, d_{\ell+1}-1\}$,
\begin{align}
\frac{s_j \Delta_{\ell}}{2}  &=   
b \mathds{1}(j\text{ odd}) +  a_{\ell+1}  \mathds{1}(j\text{ even}). \label{tmp_12}
\end{align}
Using arguments as for the rewriting of $\sum_{j=1}^{d_{\ell+1}-1} r_j \, z_{\ell+1}^{(j)}(x)$ above, 
\begin{align*}
    \sum_{j=0}^{d_{\ell+1}-1} s_j \, z_{\ell+1}^{(j)}(x) 
    &= \frac{2s_0}{D_{\ell}} \sum_{k=1}^{D_{\ell}-1}\left(x - \frac{k}{D_{\ell}}\right)_+ + \Big( \sum_{j=1}^{d_{\ell+1}-1} s_j \Big) 
    \sum_{k=1}^{D_{\ell}-1} b  \Big(x - \frac{k}{D_{\ell}}\Big)_+\\
    & \quad  + \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \frac{s_j \Delta_{\ell}}{2}
    \left( \mathds{1}(k\text{ even}) \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+
+ \mathds{1}(k\text{ odd}) \Big(x - \frac{k}{D_{\ell}} - \frac{d_{\ell+1} - j}{D_{\ell+1}}\Big)_+ \right)\\
&= \sum_{k=1}^{D_{\ell}-1} a_{\ell+1}  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \frac{s_j \Delta_{\ell}}{2}
    \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+\\
&= \sum_{k=1}^{D_{\ell}-1} a_{\ell+1}  \Big(x - \frac{k}{D_{\ell}}\Big)_+
+ \sum_{k=0}^{D_{\ell}-1} \sum_{j=1}^{d_{\ell+1}-1}
    \Big( b \mathds{1}(j\text{ odd}) + a_{\ell+1} \mathds{1}(j\text{ even}) \Big) 
    \Big(x - \frac{k}{D_{\ell}} - \frac{j}{D_{\ell+1}}\Big)_+\\
    & = \sum^{D_{\ell+1}-1}_{q=1} \Big( b \mathds{1}(q\text{ odd}) + a_{\ell+1} \mathds{1}(q\text{ even}) \Big) \Big(x - \frac{q}{D_{\ell+1}}\Big)_+ \\
    =: u^{(2)}_{\ell+1}(x)
\end{align*}
where we used \eqref{tmp_11} and \eqref{tmp_12} for the second and third equalities, respectively. Hence, $u^{(2)}_{\ell+1}(x)$ is also a non-negative affine combination of $(z^{(0)}_{\ell+1}(x))_{j=0}^{d_{\ell+1}-1}$.
Finally, we get the remaining assertion by noticing that 
$$u^{(0)}_{\ell+1}(x) = \sum_{k=1}^{D_{\ell+1}-1} \frac{2}{D_{\ell+1}} \left(x - \frac{k}{D_{\ell+1}}\right)_+ = \frac{2}{D_{\ell+1}(a_{\ell+1} + b)} \left(u^{(1)}_{\ell+1}(x) + u^{(2)}_{\ell+1}(x)\right)$$
can also be represented as a non-negative affine combination of $(z^{(0)}_{\ell+1}(x))_{j=0}^{d_{\ell+1}-1}$.
\end{proof}

